def gen(rng, size):
    n = max(1, size // 2)
    out = []
    for _ in range(n):
        k = rng.randint(1, 4)
        if rng.random() < 0.5:
            out.append('R' * k + 'L' * k)
        else:
            out.append('L' * k + 'R' * k)
    return [''.join(out)]

